// normalize_data
const pipelineItems = $('consultar_pipeline').all();
const tarefasItems = $('consultar_tarefas').all();

function norm(val) {
  if (val === null || val === undefined) return '';
  return String(val).toLowerCase().trim();
}

function parseDate(val) {
  if (!val) return null;
  const d = new Date(val);
  return isNaN(d.getTime()) ? null : d;
}

function daysDiff(dateA, dateB) {
  if (!dateA || !dateB) return null;
  const msPerDay = 1000 * 60 * 60 * 24;
  return Math.floor((dateB - dateA) / msPerDay);
}

const today = new Date();
today.setHours(0, 0, 0, 0);

const pipeline = pipelineItems.map(item => {
  const row = item.json;
  const dataInicioStatus = parseDate(row.data_inicio_status);
  const dataFollowup = parseDate(row.data_followup_realizado);
  return {
    id_followup: (row.id_followup !== null && row.id_followup !== undefined) ? String(row.id_followup).trim() : '',
    parceiro: (row.parceiro || '').trim(),
    ponto_focal: (row.ponto_focal || '').trim(),
    produto: (row.produto || '').trim(),
    status: (row.status || '').trim(),
    status_followup: (row.status_followup || '').trim(),
    parceiro_norm: norm(row.parceiro),
    ponto_focal_norm: norm(row.ponto_focal),
    produto_norm: norm(row.produto),
    status_norm: norm(row.status),
    status_followup_norm: norm(row.status_followup),
    data_inicio_status: dataInicioStatus,
    data_followup_realizado: dataFollowup,
    ultima_cadencia_feita: (row.ultima_cadencia_feita || '').trim(),
    resumo_negociacao: (row.resumo_negociacao || '').trim(),
    observacoes_gerais: (row.observacoes_gerais || '').trim(),
    _days_in_status: dataInicioStatus ? daysDiff(dataInicioStatus, today) : null,
    _days_since_followup: dataFollowup ? daysDiff(dataFollowup, today) : null,
  };
});

const tarefas = tarefasItems.map(item => {
  const row = item.json;
  const prazo = parseDate(row.prazo);
  return {
    id: (row.id !== null && row.id !== undefined) ? String(row.id).trim() : '',
    titulo: (row.titulo || '').trim(),
    prazo: prazo,
    observacao: (row.observacao || '').trim(),
    status: (row.status || '').trim(),
    status_norm: norm(row.status),
    _days_until_due: prazo ? daysDiff(today, prazo) : null,
  };
});

return [{ json: { pipeline, tarefas } }];

// score_pipeline
const { pipeline, tarefas } = $input.first().json;

const SLA = {
  'aguardando proposta': 7,
  'compliance': 3,
  'minuta com cliente': 7,
  'juridico': 10,
  'fechamento': 3,
};

function scorePipeline(item) {
  let score = 0;
  const motivo = [];

  const sla = SLA[item.status_norm] || null;
  const daysInStatus = item._days_in_status;
  const daysSinceFollowup = item._days_since_followup;
  const statusFollowup = item.status_followup_norm;

  if (sla !== null && daysInStatus !== null) {
    if (daysInStatus > sla + 7) {
      score += 5;
      motivo.push(`Status "${item.status}" excedeu SLA em mais de 7 dias (${daysInStatus} dias)`);
    } else if (daysInStatus > sla + 3) {
      score += 3;
      motivo.push(`Status "${item.status}" excedeu SLA em mais de 3 dias (${daysInStatus} dias)`);
    } else if (daysInStatus > sla) {
      score += 2;
      motivo.push(`Status "${item.status}" acima do SLA (${daysInStatus}/${sla} dias)`);
    }
  }

  if (daysSinceFollowup === null) {
    score += 2;
    motivo.push('Nenhum follow-up registrado');
  } else if (daysSinceFollowup >= 7) {
    score += 3;
    motivo.push(`Último follow-up há ${daysSinceFollowup} dias (≥7)`);
  } else if (daysSinceFollowup >= 3) {
    score += 2;
    motivo.push(`Último follow-up há ${daysSinceFollowup} dias (≥3)`);
  }

  if (item.status_norm === 'fechamento') {
    score += 3;
    motivo.push('Status em fechamento — alta prioridade');
  }
  if (item.status_norm === 'compliance') {
    score += 2;
    motivo.push('Status em compliance — requer atenção');
  }

  if (statusFollowup === 'late' || statusFollowup === 'atrasado') {
    score += 4;
    motivo.push('Follow-up está atrasado');
  } else if (statusFollowup === 'pending' || statusFollowup === 'pendente') {
    score += 2;
    motivo.push('Follow-up pendente');
  }

  return { ...item, score, motivo };
}

const scoredPipeline = pipeline.map(scorePipeline);

return [{ json: { pipeline: scoredPipeline, tarefas } }];

// score_tasks
const { pipeline, tarefas } = $input.first().json;

function scoreTarefa(item) {
  let score = 0;
  const motivo = [];
  const daysUntilDue = item._days_until_due;
  const status = item.status_norm;
  let risco = 'baixo';

  if (daysUntilDue !== null && daysUntilDue < 0) {
    score += 5;
    risco = 'alto';
    motivo.push(`Tarefa vencida há ${Math.abs(daysUntilDue)} dia(s)`);
  } else if (daysUntilDue === 0) {
    score += 4;
    risco = 'medio';
    motivo.push('Tarefa vence hoje');
  }

  if (status === 'em andamento' || status === 'in_progress' || status === 'in progress') {
    score += 2;
    motivo.push('Tarefa em andamento');
  } else if (status === 'pendente' || status === 'pending') {
    score += 1;
    motivo.push('Tarefa pendente');
  }

  return { ...item, score, motivo, risco };
}

const scoredTarefas = tarefas.map(scoreTarefa);

return [{ json: { pipeline, tarefas: scoredTarefas } }];

// merge_and_prioritize
const { pipeline, tarefas } = $input.first().json;

const SLA = {
  'aguardando proposta': 7,
  'compliance': 3,
  'minuta com cliente': 7,
  'juridico': 10,
  'fechamento': 3,
};

function getBucket(score) {
  if (score >= 6) return 'agora';
  if (score >= 3) return 'hoje';
  return 'podeEsperar';
}

function getImpacto(score) {
  if (score >= 8) return 'alto';
  if (score >= 4) return 'medio';
  return 'baixo';
}

function needsFollowup(item) {
  const sf = item.status_followup_norm;
  const daysSince = item._days_since_followup;
  if (sf === 'late' || sf === 'atrasado') return true;
  if (sf === 'pending' || sf === 'pendente') return true;
  if (daysSince === null) return true;
  if (daysSince >= 3) return true;
  return false;
}

function getPipelineRisco(item) {
  const sla = SLA[item.status_norm] || null;
  const daysInStatus = item._days_in_status;
  if (sla !== null && daysInStatus !== null) {
    if (daysInStatus > sla + 7) return 'alto';
    if (daysInStatus > sla) return 'medio';
  }
  return 'baixo';
}

function getNextBestAction(tipo, action_type, status_norm, bucket) {
  const urgencia = bucket === 'agora' ? 'alta' : bucket === 'hoje' ? 'media' : 'baixa';
  if (tipo === 'tarefa') {
    return { tipo: 'execucao', canal: 'crm', objetivo: 'executar tarefa', urgencia };
  }
  if (action_type === 'check_pipeline') {
    return { tipo: 'analise', canal: 'crm', objetivo: 'revisar negociacao', urgencia };
  }
  const objetivoMap = {
    'aguardando proposta': 'destravar proposta',
    'compliance': 'acelerar compliance',
    'juridico': 'cobrar devolutiva juridica',
    'fechamento': 'avancar fechamento',
  };
  const objetivo = objetivoMap[status_norm] || 'avancar negociacao';
  return { tipo: 'followup', canal: 'whatsapp', objetivo, urgencia };
}

const actions = [];

for (const item of pipeline) {
  const risco = getPipelineRisco(item);
  let boostedScore = item.score;
  if (risco === 'alto') boostedScore += 3;
  else if (risco === 'medio') boostedScore += 1;

  const bucket = getBucket(boostedScore);
  const impacto = getImpacto(boostedScore);
  const requiresFollowup = needsFollowup(item);
  const action_type = requiresFollowup ? 'followup' : 'check_pipeline';
  const next_best_action = getNextBestAction('pipeline', action_type, item.status_norm, bucket);

  const contato = item.ponto_focal || item.parceiro || 'responsável';

  const titulo = action_type === 'followup'
    ? `Follow-up: ${item.parceiro} — ${item.produto}`
    : `Analisar negociação: ${item.parceiro} — ${item.produto}`;

  const acao_recomendada = action_type === 'followup'
    ? `Enviar follow-up para ${contato} sobre ${item.produto}`
    : `Verificar andamento da negociação com ${item.parceiro}`;

  const tempo_estimado = action_type === 'followup' ? '2 min' : '5 min';

  const action = {
    id: item.id_followup,
    tipo: 'pipeline',
    action_type,
    parceiro: item.parceiro,
    titulo,
    motivo: item.motivo,
    impacto,
    risco,
    bucket,
    score: boostedScore,
    tempo_estimado,
    acao_recomendada,
    next_best_action,
    _requiresFollowup: requiresFollowup,
    _raw: item,
  };

  actions.push(action);
}

for (const item of tarefas) {
  const bucket = getBucket(item.score);
  const impacto = getImpacto(item.score);
  const risco = item.risco || 'baixo';
  const next_best_action = getNextBestAction('tarefa', 'execucao', null, bucket);
  const daysUntilDue = item._days_until_due;
  const tempo_estimado = (daysUntilDue !== null && daysUntilDue <= 0) ? '10 min' : '5 min';

  const action = {
    id: item.id,
    tipo: 'tarefa',
    action_type: 'execucao',
    titulo: item.titulo,
    motivo: item.motivo,
    impacto,
    risco,
    bucket,
    score: item.score,
    tempo_estimado,
    acao_recomendada: `Executar tarefa: ${item.titulo}`,
    next_best_action,
    _requiresFollowup: false,
    _raw: item,
  };

  actions.push(action);
}

actions.sort((a, b) => b.score - a.score);

const agoraAll = actions.filter(a => a.bucket === 'agora');
const hojeAll = actions.filter(a => a.bucket === 'hoje');
const podeEsperarAll = actions.filter(a => a.bucket === 'podeEsperar');

const agora = agoraAll.slice(0, 5);
const hoje = hojeAll.slice(0, 10);
const podeEsperar = podeEsperarAll.slice(0, 10);

const has_followup_actions = actions.some(a => a._requiresFollowup);

return [{ json: {
  actions,
  agora,
  hoje,
  podeEsperar,
  has_followup_actions,
  total_agora_original: agoraAll.length,
  total_hoje_original: hojeAll.length,
  total_podeEsperar_original: podeEsperarAll.length,
} }];

// filtrar_followups
const data = $input.first().json;
const all = [...(data.agora || []), ...(data.hoje || []), ...(data.podeEsperar || [])];
function isFollowup(a) {
  return a._requiresFollowup === true || a._requiresFollowup === 'true';
}
const followups = all.filter(isFollowup);
const nonFollowups = all.filter(a => !isFollowup(a));
return [{ json: { followups, nonFollowups, original: data } }];

// build_response — branch WITH follow-up messages
const mergeData = $('merge_and_prioritize').first().json;
let followupResults = [];

try {
  const fwItems = $('gerar_followup_inteligente').all();
  followupResults = fwItems.map(i => i.json);
} catch (e) {
  followupResults = [];
}

const followupMap = {};
for (const fw of followupResults) {
  if (fw.id) followupMap[fw.id] = fw.mensagem_pronta || '';
}

function buildAction(action) {
  const out = {
    id: action.id,
    tipo: action.tipo,
    action_type: action.action_type,
    titulo: action.titulo,
    motivo: (action.motivo || []).slice(0, 3),
    impacto: action.impacto,
    risco: action.risco,
    tempo_estimado: action.tempo_estimado,
    acao_recomendada: action.acao_recomendada,
    next_best_action: action.next_best_action,
  };
  if (action.tipo === 'pipeline') out.parceiro = action.parceiro;
  if (action._requiresFollowup && followupMap[action.id]) {
    out.mensagem_pronta = followupMap[action.id];
  }
  return out;
}

const response = {
  status: 'ok',
  resumo: {
    agora: mergeData.agora.length,
    hoje: mergeData.hoje.length,
    podeEsperar: mergeData.podeEsperar.length,
    total_agora_original: mergeData.total_agora_original,
    total_hoje_original: mergeData.total_hoje_original,
    total_podeEsperar_original: mergeData.total_podeEsperar_original,
  },
  agora: mergeData.agora.map(buildAction),
  hoje: mergeData.hoje.map(buildAction),
  podeEsperar: mergeData.podeEsperar.map(buildAction),
};

return [{ json: response }];
